// Calculer les timestamps des rappels
const data = $input.first().json.body || $input.first().json;

const dateRdv = new Date(`${data.rdv.date}T${data.rdv.heure}:00`);
const maintenant = new Date();

// Délais configurables (par défaut : email J-1, SMS H-2)
const delaiEmail = data.config?.delaiEmail || 24; // heures avant
const delaiSMS = data.config?.delaiSMS || 2;     // heures avant

const rappelEmail = new Date(dateRdv.getTime() - delaiEmail * 60 * 60 * 1000);
const rappelSMS = new Date(dateRdv.getTime() - delaiSMS * 60 * 60 * 1000);

const dateRdvFr = dateRdv.toLocaleDateString('fr-FR', { weekday: 'long', day: 'numeric', month: 'long' });
const heureRdvFr = dateRdv.toLocaleTimeString('fr-FR', { hour: '2-digit', minute: '2-digit' });

return [{
  json: {
    rdv: {
      ...data.rdv,
      dateFormatee: dateRdvFr,
      heureFormatee: heureRdvFr,
      dateISO: dateRdv.toISOString()
    },
    client: data.client,
    config: {
      nomEtablissement: data.config?.nomEtablissement || 'Notre établissement',
      nomGerant: data.config?.nomGerant || 'L\'équipe',
      telephone: data.config?.telephone || '',
      adresse: data.config?.adresse || ''
    },
    rappelEmail: rappelEmail.toISOString(),
    rappelSMS: rappelSMS.toISOString(),
    rappelEmailStr: rappelEmail.toLocaleString('fr-FR'),
    rappelSMSStr: rappelSMS.toLocaleString('fr-FR'),
    delaiEmailH: delaiEmail,
    delaiSMSH: delaiSMS
  }
}];
